const { C2paBuilder, C2paReader } = require('c2pa-node');
const fs = require('fs');
const crypto = require('crypto');

/**
 * Sign video with C2PA content credentials
 * Requires: X.509 certificate + private key from trusted CA
 */
async function signVideoWithC2PA(inputVideoPath, outputVideoPath, certificatePath, privateKeyPath) {
  try {
    // Load signing credentials
    const certificate = fs.readFileSync(certificatePath);
    const privateKey = fs.readFileSync(privateKeyPath);

    // Create C2PA manifest with provenance claims
    const builder = new C2paBuilder({
      claim_generator: 'Ansvar Video Security System v1.0',
      claim_generator_info: [{
        name: 'video_capture_device',
        value: 'Sony A7S III',
        device_id: 'SN:3456789012'
      }],
      assertions: [
        {
          label: 'c2pa.actions',
          data: {
            actions: [
              {
                action: 'c2pa.created',
                when: new Date().toISOString(),
                softwareAgent: 'Ansvar Security Camera System',
                digitalSourceType: 'http://cv.iptc.org/newscodes/digitalsourcetype/trainedAlgorithmicMedia'
              }
            ]
          }
        },
        {
          label: 'c2pa.hash.data',
          data: {
            algorithm: 'sha256',
            hash: crypto.createHash('sha256').update(fs.readFileSync(inputVideoPath)).digest('hex'),
            name: 'original_video_hash'
          }
        },
        {
          label: 'stds.schema-org.CreativeWork',
          data: {
            '@context': 'https://schema.org',
            '@type': 'VideoObject',
            author: {
              '@type': 'Organization',
              name: 'Ansvar Corporation',
              identifier: 'LEI:9845003EA8A5D5D52D89'
            },
            datePublished: new Date().toISOString(),
            description: 'Authenticated corporate video communication'
          }
        }
      ]
    });

    // Sign and embed manifest into video
    await builder.sign({
      inputFile: inputVideoPath,
      outputFile: outputVideoPath,
      certificate: certificate,
      privateKey: privateKey,
      signingAlgorithm: 'ps256', // RSA-PSS with SHA-256
      timestampUrl: 'http://timestamp.digicert.com' // RFC 3161 timestamp authority
    });

    console.log('✓ Video signed with C2PA credentials:', outputVideoPath);
    return true;

  } catch (error) {
    console.error('Failed to sign video with C2PA:', error);
    throw error;
  }
}

/**
 * Verify video authenticity using C2PA credentials
 * Returns: validation report with trust chain and tampering detection
 */
async function verifyVideoC2PA(videoPath) {
  try {
    const reader = new C2paReader();
    const validationResult = await reader.verify(videoPath);

    // Check validation status
    if (validationResult.isValid) {
      console.log('✓ Video authenticity VERIFIED');
      console.log('  Signed by:', validationResult.manifest.claim_generator);
      console.log('  Signature valid:', validationResult.signatureValidated);
      console.log('  Certificate trusted:', validationResult.certificateTrusted);
      console.log('  Timestamp:', validationResult.manifest.timestamp);
      console.log('  Content hash match:', validationResult.hashValidated);

      // Extract provenance history
      const actions = validationResult.manifest.assertions.find(
        a => a.label === 'c2pa.actions'
      );
      console.log('  Provenance chain:', actions?.data.actions);

      return {
        valid: true,
        trustLevel: 'high',
        signer: validationResult.manifest.claim_generator,
        timestamp: validationResult.manifest.timestamp
      };
    } else {
      console.error('✗ Video authenticity FAILED');
      console.error('  Validation errors:', validationResult.validationErrors);

      return {
        valid: false,
        trustLevel: 'none',
        errors: validationResult.validationErrors
      };
    }

  } catch (error) {
    console.error('Failed to verify C2PA credentials:', error);
    return {
      valid: false,
      trustLevel: 'none',
      errors: [error.message]
    };
  }
}

