function requireC2PACredentials(req, res, next) {
  const videoFile = req.file; // Assuming multer middleware

  if (!videoFile) {
    return res.status(400).json({ error: 'No video file uploaded' });
  }

  verifyVideoC2PA(videoFile.path)
    .then(result => {
      if (result.valid) {
        req.videoAuthentication = result;
        next();
      } else {
        res.status(403).json({ 
          error: 'Video authenticity verification failed',
          details: result.errors,
          message: 'Only videos with valid C2PA content credentials are accepted'
        });
      }
    })
    .catch(error => {
      res.status(500).json({ error: 'Verification error', details: error.message });
    });
}

