const { ethers } = require('ethers');
const { create } = require('ipfs-http-client');
const crypto = require('crypto');
const ffmpeg = require('fluent-ffmpeg');
const fs = require('fs');

/**
 * Blockchain-based video timestamping and provenance system
 * Uses Ethereum smart contract + IPFS for decentralized storage
 */

// Ethereum smart contract ABI for VideoProvenance
const VIDEO_PROVENANCE_ABI = [
  "function registerVideo(bytes32 videoHash, string ipfsHash, string metadata) public returns (uint256)",
  "function verifyVideo(bytes32 videoHash) public view returns (uint256 timestamp, address creator, string ipfsHash, bool exists)",
  "function recordModification(bytes32 originalHash, bytes32 newHash, string modificationType) public",
  "function getProvenanceChain(bytes32 videoHash) public view returns (tuple(bytes32 hash, uint256 timestamp, address actor, string action)[] memory)",
  "event VideoRegistered(bytes32 indexed videoHash, uint256 timestamp, address indexed creator)",
  "event VideoModified(bytes32 indexed originalHash, bytes32 indexed newHash, uint256 timestamp)"
];

class VideoProvenanceSystem {
  constructor(ethereumRpcUrl, contractAddress, privateKey, ipfsUrl) {
    // Connect to Ethereum network (mainnet, Polygon, or Arbitrum for lower fees)
    this.provider = new ethers.providers.JsonRpcProvider(ethereumRpcUrl);
    this.wallet = new ethers.Wallet(privateKey, this.provider);
    this.contract = new ethers.Contract(contractAddress, VIDEO_PROVENANCE_ABI, this.wallet);

    // Connect to IPFS for decentralized storage
    this.ipfs = create({ url: ipfsUrl });
  }

  /**
   * Register new video with blockchain timestamp
   * Creates immutable record of video hash, upload time, and creator
   */
  async registerVideo(videoPath, metadata = {}) {
    try {
      console.log('Step 1: Calculating video hash...');
      const videoHash = await this._calculateVideoHash(videoPath);
      const videoHashBytes32 = ethers.utils.formatBytes32String(videoHash.slice(0, 32));

      console.log('Step 2: Uploading video to IPFS...');
      const videoBuffer = fs.readFileSync(videoPath);
      const ipfsResult = await this.ipfs.add(videoBuffer, {
        pin: true,  // Pin to prevent garbage collection
        wrapWithDirectory: false
      });
      const ipfsCid = ipfsResult.cid.toString();

      console.log('Step 3: Extracting video metadata...');
      const videoMetadata = await this._extractMetadata(videoPath);
      const enrichedMetadata = {
        ...metadata,
        ...videoMetadata,
        uploadTimestamp: new Date().toISOString(),
        ipfsCid: ipfsCid
      };

      console.log('Step 4: Recording on Ethereum blockchain...');
      const tx = await this.contract.registerVideo(
        videoHashBytes32,
        ipfsCid,
        JSON.stringify(enrichedMetadata),
        {
          gasLimit: 500000,
          // Use EIP-1559 gas pricing for Ethereum mainnet
          maxFeePerGas: ethers.utils.parseUnits('50', 'gwei'),
          maxPriorityFeePerGas: ethers.utils.parseUnits('2', 'gwei')
        }
      );

      console.log('Transaction submitted:', tx.hash);
      const receipt = await tx.wait();

      // Extract registration event
      const event = receipt.events.find(e => e.event === 'VideoRegistered');
      const blockTimestamp = (await this.provider.getBlock(receipt.blockNumber)).timestamp;

      console.log('✓ Video registered on blockchain');

      return {
        success: true,
        videoHash: videoHash,
        ipfsCid: ipfsCid,
        blockchainTxHash: tx.hash,
        blockNumber: receipt.blockNumber,
        timestamp: blockTimestamp,
        provenanceUrl: `https://etherscan.io/tx/${tx.hash}`,
        ipfsGatewayUrl: `https://ipfs.io/ipfs/${ipfsCid}`,
        verificationCode: this._generateVerificationCode(videoHash, blockTimestamp)
      };

    } catch (error) {
      console.error('Failed to register video:', error);
      throw error;
    }
  }

  /**
   * Verify video authenticity against blockchain record
   * Returns: provenance chain, timestamp, and tampering detection
   */
  async verifyVideo(videoPath) {
    try {
      const videoHash = await this._calculateVideoHash(videoPath);
      const videoHashBytes32 = ethers.utils.formatBytes32String(videoHash.slice(0, 32));

      // Query blockchain for video record
      const [timestamp, creator, ipfsHash, exists] = await this.contract.verifyVideo(videoHashBytes32);

      if (!exists) {
        return {
          verified: false,
          status: 'NOT_REGISTERED',
          message: 'Video hash not found in blockchain. Either never registered or content has been modified.',
          videoHash: videoHash
        };
      }

      // Retrieve full provenance chain
      const provenanceChain = await this.contract.getProvenanceChain(videoHashBytes32);

      // Verify video content matches IPFS record
      let ipfsVerified = false;
      try {
        const ipfsContent = [];
        for await (const chunk of this.ipfs.cat(ipfsHash)) {
          ipfsContent.push(chunk);
        }
        const ipfsBuffer = Buffer.concat(ipfsContent);
        const ipfsVideoHash = crypto.createHash('sha256').update(ipfsBuffer).digest('hex');
        ipfsVerified = (ipfsVideoHash === videoHash);
      } catch (error) {
        console.warn('IPFS verification failed:', error);
      }

      return {
        verified: true,
        status: 'AUTHENTIC',
        message: 'Video hash matches blockchain record. Content has not been altered since registration.',
        videoHash: videoHash,
        registrationTimestamp: new Date(timestamp.toNumber() * 1000).toISOString(),
        creator: creator,
        ipfsCid: ipfsHash,
        ipfsContentMatch: ipfsVerified,
        provenanceChain: provenanceChain.map(entry => ({
          hash: entry.hash,
          timestamp: new Date(entry.timestamp.toNumber() * 1000).toISOString(),
          actor: entry.actor,
          action: entry.action
        })),
        blockchainExplorerUrl: `https://etherscan.io/address/${creator}`,
        trustLevel: ipfsVerified ? 'HIGH' : 'MEDIUM'
      };

    } catch (error) {
      console.error('Verification failed:', error);
      throw error;
    }
  }

  /**
   * Record video modification on blockchain
   * Maintains audit trail of all edits
   */
  async recordModification(originalVideoPath, modifiedVideoPath, modificationType) {
    try {
      const originalHash = await this._calculateVideoHash(originalVideoPath);
      const modifiedHash = await this._calculateVideoHash(modifiedVideoPath);

      const originalHashBytes32 = ethers.utils.formatBytes32String(originalHash.slice(0, 32));
      const modifiedHashBytes32 = ethers.utils.formatBytes32String(modifiedHash.slice(0, 32));

      const tx = await this.contract.recordModification(
        originalHashBytes32,
        modifiedHashBytes32,
        modificationType,
        { gasLimit: 300000 }
      );

      const receipt = await tx.wait();

      console.log('✓ Modification recorded on blockchain');

      return {
        success: true,
        originalHash: originalHash,
        modifiedHash: modifiedHash,
        txHash: tx.hash,
        blockNumber: receipt.blockNumber
      };

    } catch (error) {
      console.error('Failed to record modification:', error);
      throw error;
    }
  }

  /**
   * Calculate cryptographic hash of video file
   * Uses SHA-256 of frame sequence to detect any content changes
   */
  async _calculateVideoHash(videoPath) {
    return new Promise((resolve, reject) => {
      const hash = crypto.createHash('sha256');
      const stream = fs.createReadStream(videoPath);

      stream.on('data', (chunk) => hash.update(chunk));
      stream.on('end', () => resolve(hash.digest('hex')));
      stream.on('error', reject);
    });
  }

  /**
   * Extract video metadata (duration, resolution, codec, creation date)
   */
  async _extractMetadata(videoPath) {
    return new Promise((resolve, reject) => {
      ffmpeg.ffprobe(videoPath, (err, metadata) => {
        if (err) return reject(err);

        const videoStream = metadata.streams.find(s => s.codec_type === 'video');

        resolve({
          duration: metadata.format.duration,
          size: metadata.format.size,
          format: metadata.format.format_name,
          codec: videoStream?.codec_name,
          resolution: `${videoStream?.width}x${videoStream?.height}`,
          frameRate: videoStream?.r_frame_rate,
          bitrate: metadata.format.bit_rate
        });
      });
    });
  }

  /**
   * Generate human-readable verification code
   * Format: ANSVAR-YYYYMMDD-XXXXX
   */
  _generateVerificationCode(videoHash, timestamp) {
    const date = new Date(timestamp * 1000).toISOString().slice(0, 10).replace(/-/g, '');
    const shortHash = videoHash.slice(0, 10).toUpperCase();
    return `ANSVAR-${date}-${shortHash}`;
  }
}

